   273→                let entry = parent_table.entry(key.clone()).or_insert_with(|| {
   274→                    let mut array = DeArray::new();
   275→                    array.set_array_of_tables(true);
   276→                    Spanned::new(header_span, DeValue::Array(array))
   277→                });
