   380→                                ParseError::new(
   381→                                    "cannot extend value of type array with a dotted key",
   382→                                )
   383→                                .with_unexpected(key_span)
   384→                                .with_context(old_span),
   385→                            );
   386→                            return None;
   387→                        }
   388→
   389→                        debug_assert!(!array.is_empty());
